SELECT [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Constant Variable Code] AS ColorCode, [Variable Code].Description AS ColorDescription, Sum(IIf([Sales Line.document type]=1,Val([No_ of Pairs]),-Val([No_ of Pairs]))) AS PairsSold, [Sales Header].[Selling Season Code] AS [SEASON CODE], [Sales Header].[shortcut dimension 2 code] AS [Trademark code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])) LEFT JOIN [Sales Header Extension] ON ([Sales Header].No_ = [Sales Header Extension].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Header Extension].[Document Type])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19) AND (([Sales Header].[Order Type])=0 Or ([Sales Header].[Order Type])=2) AND (([Sales Line].[delete reason])="ART" Or ([Sales Line].[delete reason])=""))
GROUP BY [Sales Line].No_, [Sales Line].[Constant Variable Code], [Sales Line].[Constant Variable Code], [Variable Code].Description, [Sales Header].[Selling Season Code], [Sales Header].[shortcut dimension 2 code], [Sales Line].[Constant Variable Code] AND  ([Season Code]='I25') and ([Trademark Code]='BLAUER');

